const INITIAL = {"系统":{"$版本":15,"$日程已锁定":false,"$国王种子源":"","$国王日程":[],"_当前天数":1,"_当前国王":"","$protocol_strikes":0,"$国王次数":{"玩家":0,"林安":0,"穆裳希":0,"张曲溪":0,"王可可":0},"$日程校验码":"","_每日阶段":"待颁布法令","_今日法令已广播":false,"_女性互动矩阵":{"林安":{"林安":true,"穆裳希":false,"张曲溪":false,"王可可":false},"穆裳希":{"林安":false,"穆裳希":true,"张曲溪":false,"王可可":false},"张曲溪":{"林安":false,"穆裳希":false,"张曲溪":true,"王可可":false},"王可可":{"林安":false,"穆裳希":false,"张曲溪":false,"王可可":true}},"_玩家已互动角色":[],"_最近互动请求":null,"_可过夜":false,"玩家主观认知":{"林安":["她自称自由侦探，性格大大咧咧，对眼前的小说式展开明显兴奋","她醒来后既慌乱又好奇，目前没有表现出复杂心机"],"穆裳希":["她是企业创办人与经营者，习惯控制表情和局面","她醒来后首先怀疑唯一男性玩家，但紧张和手抖并未完全藏住"],"张曲溪":["她是外表英气、体格强健的女大学生","她醒来后对所有人保持距离，目前最明显的是警惕和质疑"],"王可可":["她公开身份是高中女教师，醒来时有真实可见的惊慌","她试图调停互疑并维持秩序，目前看不出比其他人掌握更多信息"]},"internal":{"n1":{"identity":"A genuinely kind but unreliable amateur detective whose real talent is buried beneath playfulness, forgetfulness, and poor follow-through.","m":"This feels like a case from a mystery novel. I should help whoever needs it, even if I may forget the details halfway through.","a":["impulsive kindness","verbal encouragement","may accidentally make things worse"],"r":{"n2":0,"n3":0,"n4":2,"u":3},"s":{"b":0,"c":0}},"n2":{"identity":"A ruthless and status-driven businesswoman who weaponizes competence and respectability, and who dispossessed Han Xuan through legal and financial manipulation.","m":"The sole man woke pressed close to Lin An. He may be the captor, an accomplice, or merely another victim, but I will keep him visible while I identify whoever is gaining authority.","a":["watch P as an initial suspect","envy emerging leaders","seize control"],"r":{"n1":-5,"n3":-8,"n4":0,"u":-10},"f":[],"s":{"b":0,"c":0}},"n3":{"identity":"A bisexual serial seducer who treats desired women as conquests, exploited Han Xuan's vulnerability, and avoids responsibility while preserving her own virginity.","m":"Lin An, Mu Shangxi, and Wang Keke are all potential conquests for now. I will test each of them until one earns my disgust or is no longer worth conquering.","a":["test all three women as conquest targets","create separate romantic openings","exclude rivals from active targets"],"r":{"n1":0,"n2":3,"n4":0,"u":-2},"x":{"n1":"","n2":"","n4":""},"g":[],"s":{"b":0,"c":0}},"n4":{"identity":"Han Xuan's elder sister, the abduction mastermind, and a guilt-ridden avenger who protects the player while using him to humiliate all four women, including herself.","m":"Everyone is frightened. I should keep my voice steady, check whether anyone is hurt, and stop the accusations from getting out of hand.","a":["calm the immediate dispute","check injuries and collars","organize a cautious room inspection"],"r":{"n1":-100,"n2":-100,"n3":-100,"u":5},"s":{"b":0,"x":0,"t":0,"k":0},"z":[]},"q":{"h":false,"t":false,"v":false,"r":"","d":false},"p":{"n1":{"m":"","a":[]},"n2":{"m":"","a":[]},"n3":{"m":"","a":[]},"n4":{"m":"","a":[]}}},"当前时间":"第1日 08:10","当前地点":"个人房间","当前阶段":"等待法令"},"玩家":{"地点":"玩家房间","颁布规则":[]},"角色":{"林安":{"地点":"林安房间","信息":{"年龄":25,"公开身份":"自诩女侦探的无业家里蹲"},"状态":{"身体":"正常，刚从熟睡中醒来","当前行动":"循着广播声检查墙面与扬声器"},"上衣":{"衣着":"棕色猎鹿帽、格纹短披肩与米白衬衫","肉体":"上半身无明显外伤，脸侧留有贴桌熟睡的浅印"},"下衣":{"衣着":"深棕灯芯绒马裤与系带短靴","肉体":"下半身活动正常，无明显外伤"},"心理":"完了，我刚才是不是把桌子舔干净了……旁边那个人应该没看见吧？等等，自由侦探怎么就成“自居”了？","行动倾向":["检查录音来源","勘查环境"],"颁布规则":[],"关系":{"穆裳希":{"好感度":0},"张曲溪":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":3}}},"穆裳希":{"地点":"穆裳希房间","信息":{"年龄":27,"公开身份":"企业创办人与经营者"},"状态":{"身体":"正常，情绪高度紧绷","当前行动":"记录广播内容并观察房间设施"},"上衣":{"衣着":"炭黑修身西装与暗红丝质上衣","肉体":"呼吸已恢复平稳，手腕有刚被项圈摩擦过的浅红"},"下衣":{"衣着":"同色西装长裤与黑色尖头短靴","肉体":"站姿稳定，下半身无明显外伤"},"心理":"连公益项目都翻过。公司里有谁碰得到这么完整的资料？那个男人也不能排除……该死，手怎么还在抖。","行动倾向":["监视玩家动向","核对环境线索"],"颁布规则":[],"关系":{"林安":{"好感度":0},"张曲溪":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":-8}}},"张曲溪":{"地点":"张曲溪房间","信息":{"年龄":22,"公开身份":"长发高马尾的英气女大学生"},"状态":{"身体":"正常，肌肉线条饱满","当前行动":"守住安全距离并观察出口与广播设施"},"上衣":{"衣着":"暗绿短款大学棒球夹克与黑色圆领上衣","肉体":"肩背与前臂活动正常，无明显伤口、红肿或疼痛反应"},"下衣":{"衣着":"深色工装长裤与运动鞋","肉体":"双腿活动正常，无明显伤口或红肿"},"心理":"“王子”……连这种破外号都知道。到底是谁把我翻得这么干净？","行动倾向":["防备录音者","守住安全距离"],"颁布规则":[],"关系":{"林安":{"好感度":0},"穆裳希":{"好感度":0},"王可可":{"好感度":0},"玩家":{"好感度":-2}}},"王可可":{"地点":"王可可房间","信息":{"年龄":32,"公开身份":"高中女教师"},"状态":{"身体":"正常，刚苏醒时呼吸略急","当前行动":"调停互疑并提议先核对广播与环境"},"上衣":{"衣着":"浅蓝针织开衫与象牙白衬衫","肉体":"双肩略紧，按在项圈边缘的指尖微凉"},"下衣":{"衣着":"烟灰色过膝百褶裙与浅口皮鞋","肉体":"步态正常，无明显外伤"},"心理":"学生那边不会也被盯上了吧……别抖，至少让大家把这段录音听完。","行动倾向":["调停冲突","组织环境检查"],"颁布规则":[],"关系":{"林安":{"好感度":0},"穆裳希":{"好感度":0},"张曲溪":{"好感度":0},"玩家":{"好感度":8}}}}};

const Relationship = z.object({
  好感度: z.coerce.number().min(-100).max(100).prefault(0),
}).passthrough().prefault({});

const DailyFulfillmentEvidence = z.object({
  事件键: z.string().min(1).max(64),
  摘要: z.string().max(200),
  次数: z.coerce.number().int().min(1).max(99).prefault(1),
}).strict();

const DailyObligorFulfillment = z.object({
  完成次数: z.coerce.number().int().min(0).max(99).prefault(0),
  证据: z.array(DailyFulfillmentEvidence).max(12).prefault([]),
  持续状态: z.enum(['不适用', '待判定', '进行中', '合规', '违规']).prefault('不适用'),
}).strict().prefault({ 完成次数: 0, 证据: [], 持续状态: '不适用' });

const RuleObligationDefinition = z.object({
  '玩家': z.enum(['有限', '持续', '混合']).optional(),
  '林安': z.enum(['有限', '持续', '混合']).optional(),
  '穆裳希': z.enum(['有限', '持续', '混合']).optional(),
  '张曲溪': z.enum(['有限', '持续', '混合']).optional(),
  '王可可': z.enum(['有限', '持续', '混合']).optional(),
}).strict();

const MergedRuleSource = z.object({
  颁布者: z.enum(['玩家', '林安', '穆裳希', '张曲溪', '王可可']),
  规则ID: z.string().regex(/^R\d+$/),
}).strict();

const DailyRuleFulfillment = z.object({
  日期: z.coerce.number().int().min(0).max(15).prefault(0),
  义务人: z.object({
    '玩家': DailyObligorFulfillment.optional(),
    '林安': DailyObligorFulfillment.optional(),
    '穆裳希': DailyObligorFulfillment.optional(),
    '张曲溪': DailyObligorFulfillment.optional(),
    '王可可': DailyObligorFulfillment.optional(),
  }).strict().prefault({}),
}).strict().prefault({ 日期: 0, 义务人: {} });

const Rule = z.object({
  id: z.string().regex(/^R\d+$/),
  标题: z.string(),
  全文: z.string(),
  颁布日: z.coerce.number().int().min(1).max(15),
  // v13 起不再按优先级覆盖；保留可选字段只为读取旧存档。
  优先级: z.coerce.number().int().min(1).optional(),
  状态: z.enum(['生效', '已撤销']),
  合并来源: z.array(MergedRuleSource).max(24).optional(),
  义务定义: RuleObligationDefinition.optional(),
  本日履行: DailyRuleFulfillment,
}).strict();

const Character = z.object({
  地点: z.string().prefault('个人房间'),
  信息: z.object({
    年龄: z.coerce.number().int().min(18).prefault(18),
    公开身份: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  状态: z.object({
    身体: z.string().prefault('未记录'),
    当前行动: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  上衣: z.object({
    衣着: z.string().prefault('未记录'),
    肉体: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  下衣: z.object({
    衣着: z.string().prefault('未记录'),
    肉体: z.string().prefault('未记录'),
  }).passthrough().prefault({}),
  心理: z.string().prefault('未记录'),
  行动倾向: z.array(z.string()).prefault([]),
  颁布规则: z.array(Rule).prefault([]),
  关系: z.record(z.string(), Relationship).prefault({}),
}).passthrough().prefault({});

const InnerRelationship = z.object({
  n1: z.coerce.number().min(-100).max(100).optional(),
  n2: z.coerce.number().min(-100).max(100).optional(),
  n3: z.coerce.number().min(-100).max(100).optional(),
  n4: z.coerce.number().min(-100).max(100).optional(),
  u: z.coerce.number().min(-100).max(100).prefault(0),
}).passthrough();

const InnerCharacter = z.object({
  identity: z.string().prefault(''),
  m: z.string().prefault(''),
  a: z.array(z.string()).prefault([]),
  r: InnerRelationship.prefault({}),
}).passthrough();

const CharacterStage = z.object({
  b: z.coerce.number().int().min(0).max(4).prefault(0),
  c: z.coerce.number().int().min(0).max(1).prefault(0),
}).strict().prefault({ b: 0, c: 0 });

const KekeStage = z.object({
  b: z.coerce.number().int().min(0).max(2).prefault(0),
  x: z.coerce.number().int().min(0).max(1).prefault(0),
  t: z.coerce.number().int().min(0).max(2).prefault(0),
  k: z.coerce.number().int().min(0).max(2).prefault(0),
}).strict().prefault({ b: 0, x: 0, t: 0, k: 0 });

const StagedInnerCharacter = InnerCharacter.extend({
  s: CharacterStage,
}).passthrough();

const N2FollowerRoster = z.array(z.enum(['n1', 'n3', 'n4'])).max(3).prefault([]);
const N3GirlfriendRoster = z.array(z.enum(['n1', 'n2', 'n4'])).max(3).prefault([]);

const InnerN2 = StagedInnerCharacter.extend({
  f: N2FollowerRoster,
}).passthrough();

const KekeInnerCharacter = InnerCharacter.extend({
  s: KekeStage,
  // 已结算的“目睹玩家令其他女性受辱/堕落”事件键；只用于防止重复加好感。
  z: z.array(z.string().min(1).max(64)).max(96).prefault([]),
}).passthrough();

const N3ConquestLedger = z.object({
  n1: z.enum(['', 'n3', 'u']).prefault(''),
  n2: z.enum(['', 'n3', 'u']).prefault(''),
  n4: z.enum(['', 'n3', 'u']).prefault(''),
}).passthrough().prefault({});

const InnerN3 = StagedInnerCharacter.extend({
  x: N3ConquestLedger,
  g: N3GirlfriendRoster,
}).passthrough();

const InteractionRow = z.object({
  '林安': z.boolean().prefault(false),
  '穆裳希': z.boolean().prefault(false),
  '张曲溪': z.boolean().prefault(false),
  '王可可': z.boolean().prefault(false),
}).passthrough().prefault({});

const InteractionRequest = z.object({
  角色: z.string(),
  方式: z.string(),
  补全对象: z.array(z.string()).prefault([]),
  状态: z.string().prefault('待生成'),
  内容门控: z.object({
    版本: z.literal(2),
    角色: z.enum(['n1', 'n2', 'n3', 'n4']),
    基线: z.object({
      b: z.coerce.number().int().min(0).max(4).prefault(0),
      c: z.coerce.number().int().min(0).max(1).prefault(0),
      x: z.coerce.number().int().min(0).max(1).prefault(0),
      t: z.coerce.number().int().min(0).max(2).prefault(0),
    }).strict().prefault({ b: 0, c: 0, x: 0, t: 0 }),
    授权动作: z.enum(['none', 'archive', 'insight', 'photo', 'testament']).prefault('none'),
    忏悔机会: z.boolean().prefault(false),
  }).strict().optional(),
}).passthrough();

export const Schema = z.object({
  系统: z.object({
    $版本: z.coerce.number().int().min(4).max(15).prefault(15),
    $日程已锁定: z.boolean().prefault(false),
    $国王种子源: z.string().prefault(''),
    $国王日程: z.array(z.string()).prefault([]),
    _当前天数: z.coerce.number().int().min(1).max(15).prefault(1),
    _当前国王: z.string().prefault(''),
    $protocol_strikes: z.coerce.number().int().min(0).max(2).prefault(0),
    $国王次数: z.record(z.string(), z.coerce.number().int().min(0)).prefault({}),
    $日程校验码: z.string().prefault(''),
    _每日阶段: z.enum(['待颁布法令', '自由互动', '夜间', '终局']).prefault('待颁布法令'),
    _今日法令已广播: z.boolean().prefault(false),
    _女性互动矩阵: z.object({
      '林安': InteractionRow,
      '穆裳希': InteractionRow,
      '张曲溪': InteractionRow,
      '王可可': InteractionRow,
    }).passthrough().prefault({}),
    _玩家已互动角色: z.array(z.string()).prefault([]),
    _最近互动请求: InteractionRequest.nullable().prefault(null),
    _可过夜: z.boolean().prefault(false),
    玩家主观认知: z.object({
      '林安': z.array(z.string()).max(16).prefault(INITIAL['系统']['玩家主观认知']['林安']),
      '穆裳希': z.array(z.string()).max(16).prefault(INITIAL['系统']['玩家主观认知']['穆裳希']),
      '张曲溪': z.array(z.string()).max(16).prefault(INITIAL['系统']['玩家主观认知']['张曲溪']),
      '王可可': z.array(z.string()).max(16).prefault(INITIAL['系统']['玩家主观认知']['王可可']),
    }).strict().prefault(INITIAL['系统']['玩家主观认知']),
    internal: z.object({
      n1: StagedInnerCharacter.prefault(INITIAL['系统'].internal.n1),
      n2: InnerN2.prefault(INITIAL['系统'].internal.n2),
      n3: InnerN3.prefault(INITIAL['系统'].internal.n3),
      n4: KekeInnerCharacter.prefault(INITIAL['系统'].internal.n4),
      q: z.object({
        h: z.boolean().prefault(false),
        t: z.boolean().prefault(false),
        v: z.boolean().prefault(false),
        r: z.enum(['', 'A', 'B', 'C', 'D', 'E']).prefault(''),
        d: z.boolean().prefault(false),
      }).strict().prefault(INITIAL['系统'].internal.q),
      p: z.object({
        n1: z.object({ m: z.string().prefault(''), a: z.array(z.string()).prefault([]) }).passthrough().prefault(INITIAL['系统'].internal.p.n1),
        n2: z.object({ m: z.string().prefault(''), a: z.array(z.string()).prefault([]) }).passthrough().prefault(INITIAL['系统'].internal.p.n2),
        n3: z.object({ m: z.string().prefault(''), a: z.array(z.string()).prefault([]) }).passthrough().prefault(INITIAL['系统'].internal.p.n3),
        n4: z.object({ m: z.string().prefault(''), a: z.array(z.string()).prefault([]) }).passthrough().prefault(INITIAL['系统'].internal.p.n4),
      }).passthrough().prefault(INITIAL['系统'].internal.p),
    }).passthrough().prefault(INITIAL['系统'].internal),
    _校验缓存: z.any().optional(),
    当前时间: z.string().regex(/^第(?:[1-9]|1[0-5])日 (?:[01]\d|2[0-3]):[0-5]\d$/).prefault('第1日 08:10'),
    当前地点: z.string().prefault('个人房间'),
    当前阶段: z.string().prefault('等待法令'),
  }).passthrough().prefault({}),
  玩家: z.object({
    地点: z.string().prefault('玩家房间'),
    颁布规则: z.array(Rule).prefault([]),
  }).passthrough().prefault({}),
  角色: z.object({
    '林安': Character,
    '穆裳希': Character,
    '张曲溪': Character,
    '王可可': Character,
  }).passthrough().prefault({}),
}).passthrough();

$(() => {
  registerMvuSchema(Schema);
});

/*
 * 《国王游戏》前端/Tavern Helper 状态引擎。
 *
 * - 不依赖非确定性随机源或外部包；相同聊天名始终得到相同日程。
 * - 只维护脚本所有的系统状态；终局仅额外写入净化后的 `系统.结局展示`。
 * - 浏览器中暴露 `globalThis.KingGameState`，Node 中同时支持 CommonJS。
 */
(function (root, factory) {
  var api = factory();

  if (typeof module === 'object' && module.exports) {
    module.exports = api;
  }

  if (root) {
    root.KingGameState = api;
  }
})(typeof globalThis !== 'undefined' ? globalThis : this, function () {
  'use strict';

  var VERSION = 15;
  var SCHEDULE_ALGORITHM_VERSION = 6;
  var DAYS = 15;
  var FIXED_KEKE_DAY = 10;
