  var SCHEDULE_CODES = ['bravo', 'delta', 'echo', 'alpha', 'charlie'];
  var CODE_TO_NAME = { alpha: '张曲溪', bravo: '玩家', charlie: '王可可', delta: '林安', echo: '穆裳希' };
  var NAME_TO_CODE = { '玩家': 'bravo', '林安': 'delta', '穆裳希': 'echo', '张曲溪': 'alpha', '王可可': 'charlie' };
  var WOMEN = ['林安', '穆裳希', '张曲溪', '王可可'];
  var RELATIONSHIP_DECREE_TEXT = '每个人必须说出自己和韩璇的关系';
  var ENDING_NAMES = { n1: '林安', n2: '穆裳希', n3: '张曲溪' };
  var INNER_NAMES = { n1: '林安', n2: '穆裳希', n3: '张曲溪', n4: '王可可', u: '玩家' };
  var ARCHIVE_ALIAS_BY_NAME = { '林安': 'n1', '穆裳希': 'n2', '张曲溪': 'n3', '王可可': 'n4' };
  var ARCHIVE_ALIASES = ['n1', 'n2', 'n3', 'n4'];
  var FOLLOWER_CANDIDATES = ['n1', 'n3', 'n4'];
  var GIRLFRIEND_CANDIDATES = ['n1', 'n2', 'n4'];
  var CANONICAL_IDENTITIES = {
    n1: 'A genuinely kind but unreliable amateur detective whose real talent is buried beneath playfulness, forgetfulness, and poor follow-through.',
    n2: 'A ruthless and status-driven businesswoman who weaponizes competence and respectability, and who dispossessed Han Xuan through legal and financial manipulation.',
    n3: "A bisexual serial seducer who treats desired women as conquests, exploited Han Xuan's vulnerability, and avoids responsibility while preserving her own virginity.",
    n4: "Han Xuan's elder sister, the abduction mastermind, and a guilt-ridden avenger who protects the player while using him to humiliate all four women, including herself."
  };
  var ENDING_TITLES = {
    A: '唯一幸存者',
    B: '迟来的残片',
    C: '完整的忏悔',
    D: '余生同路',
    E: '越权者的终止'
  };
